module.render:
const color = args.color || 'var(--accent-color)';
const rings = sections.map((s) => (s || '').trim()).filter(Boolean);
if (!rings.length) return `<div>(target: one ring per section, innermost first)</div>`;
const n = rings.length;
// outermost ring first in DOM (stacked), label pinned to the top area of its ring band
let html = `\n\n<div class="mdp-mod-target" style="--tg-c:${color};"><div class="mdp-tg-stack" style="--tg-n:${n};">`;
for (let i = n - 1; i >= 0; i--) {
  const k = i + 1; // 1..n from center
  const pct = (k / n) * 100;
  const opacity = (0.10 + 0.5 * (1 - i / n)).toFixed(2);
  html += `<div class="mdp-tg-ring" style="width:${pct}%; height:${pct}%; background: color-mix(in srgb, var(--tg-c) ${(opacity * 100).toFixed(0)}%, transparent); z-index:${n - i};">` +
    `<div class="mdp-tg-label${i === 0 ? ' mdp-tg-core' : ''}">\n\n${rings[i]}\n\n</div></div>`;
}
html += `</div></div>\n\n`;
return html;
